export function script(input) {
  function normalize(value) {
    return String(value || '').toLowerCase().replace(/^https?:\/\//, '').replace(/\/.*$/, '').replace(/\.$/, '').trim();
  }
  function validHostname(value) {
    return /^[a-z0-9.-]+\.[a-z]{2,}$/i.test(value);
  }
  const discovered = Array.isArray(input.discoveredSubdomains) ? input.discoveredSubdomains : [];
  const known = Array.isArray(input.knownSubdomains) ? input.knownSubdomains : [];
  const knownNormalized = Array.from(new Set(known.map(normalize).filter(validHostname)));
  const discoveredNormalized = Array.from(new Set(discovered.map(normalize).filter(validHostname))).filter((value) => !knownNormalized.includes(value)).slice(0, 100);
  return { subdomains: [...knownNormalized, ...discoveredNormalized] };
}

export function script(input) {
  const dnsResults = Array.isArray(input.dnsResults) ? input.dnsResults : [];
  const httpResponses = Array.isArray(input.httpResponses) ? input.httpResponses : [];
  const nucleiFindings = Array.isArray(input.nucleiFindings) ? input.nucleiFindings : [];
  const servicePattern = /(github\.io|herokuapp\.com|azurewebsites\.net|cloudfront\.net|s3\.amazonaws\.com|pages\.dev|netlify\.app|vercel\.app|surge\.sh|bitbucket\.io|readme\.io|zendesk\.com|freshdesk\.com)/i;
  const bodyPattern = /(no such app|repository not found|project not found|there isn't a github pages site here|bucket not found|no such bucket|domain is not configured|unknown site|there is no app configured)/i;
  const candidates = new Map();
  function normalizeHost(value) {
    const text = String(value || '').trim();
    if (!text) return '';
    try { return new URL(text).hostname.toLowerCase(); } catch { return text.replace(/^https?:\/\//i, '').replace(/\/.*$/, '').replace(/:\d+$/, '').replace(/\.$/, '').toLowerCase(); }
  }
  function ensureCandidate(host) {
    const normalized = normalizeHost(host);
    if (!normalized) return null;
    if (!candidates.has(normalized)) candidates.set(normalized, { host: normalized, confidence: 'needs_manual_review', priorityScore: 0, reasons: [], dnsEvidence: [], httpEvidence: [], nucleiFindings: [] });
    return candidates.get(normalized);
  }
  function addReason(candidate, reason) {
    if (!candidate.reasons.includes(reason)) candidate.reasons.push(reason);
  }
  function answerValues(value) {
    if (Array.isArray(value)) return value.flatMap(answerValues);
    if (value && typeof value === 'object') return Object.values(value).flatMap(answerValues);
    return value ? [String(value)] : [];
  }
  for (const finding of nucleiFindings) {
    const host = normalizeHost(finding?.host || finding?.matchedAt || finding?.url || finding?.target);
    const candidate = ensureCandidate(host);
    if (!candidate) continue;
    candidate.confidence = 'confirmed';
    candidate.priorityScore += 100;
    candidate.nucleiFindings.push({ templateId: finding?.templateId || finding?.templateID || finding?.id || null, severity: finding?.severity || null, name: finding?.name || finding?.info?.name || null, matchedAt: finding?.matchedAt || finding?.url || finding?.host || null });
    addReason(candidate, 'Nuclei takeover template matched');
  }
  for (const record of dnsResults) {
    const host = normalizeHost(record?.host || record?.input || record?.name || record?.domain);
    const cnameValues = answerValues([record?.cname, record?.cnames, record?.CNAME, record?.answers?.cname, record?.answers?.CNAME]);
    const matching = cnameValues.filter((value) => servicePattern.test(value));
    if (matching.length === 0) continue;
    const candidate = ensureCandidate(host);
    if (!candidate) continue;
    candidate.priorityScore += 40;
    candidate.dnsEvidence.push({ host, cname: matching });
    addReason(candidate, `CNAME points to takeover-prone service: ${matching.join(', ')}`);
  }
  for (const response of httpResponses) {
    const host = normalizeHost(response?.input || response?.host || response?.url || response?.finalUrl);
    const text = [response?.title, response?.body, response?.raw, response?.tech, response?.webserver].join(' ');
    if (!bodyPattern.test(text)) continue;
    const candidate = ensureCandidate(host);
    if (!candidate) continue;
    candidate.priorityScore += 30;
    candidate.httpEvidence.push({ url: response?.url || response?.finalUrl || response?.input || host, statusCode: response?.statusCode || response?.status, title: response?.title || null });
    addReason(candidate, 'HTTP response contains takeover-like error text');
  }
  const ranked = Array.from(candidates.values()).map((candidate) => ({ ...candidate, priorityScore: candidate.confidence === 'confirmed' ? candidate.priorityScore + 25 : candidate.priorityScore })).sort((a, b) => b.priorityScore - a.priorityScore || a.host.localeCompare(b.host));
  return { report: { summary: { candidates: ranked.length, confirmed: ranked.filter((item) => item.confidence === 'confirmed').length, needsManualReview: ranked.filter((item) => item.confidence !== 'confirmed').length, dnsSignals: dnsResults.length, httpSignals: httpResponses.length, nucleiFindings: nucleiFindings.length }, candidates: ranked, dnsSignals: dnsResults.slice(0, 200), httpSignals: httpResponses.slice(0, 200), nucleiFindings, nextSteps: ['Manually verify dangling service ownership before reporting', 'Confirm the hostname is in authorized scope', 'Do not claim impact from DNS or HTTP hints alone'] } };
}
